commits.content:
import { Sequelize } from 'sequelize';

const sequelize = new Sequelize({
  dialect: 'sqlite',
  storage: './database.sqlite',
  logging: false, // يمكن تفعيله لرؤية استعلامات SQL
});

export default sequelize;
